import socket

# Résolution DNS
def resoudre_domaine(domaine):
    try:
        ip = socket.gethostbyname(domaine)
        return ip
    except socket.gaierror as e:
        return f"Erreur DNS : {e}"

print(resoudre_domaine("google.com"))
print(resoudre_domaine("malware-c2.xyz"))  # Peut retourner une IP ou erreur

# Résolution inverse (IP → domaine)
def resoudre_inverse(ip):
    try:
        hostname = socket.gethostbyaddr(ip)[0]
        return hostname
    except socket.herror:
        return "Pas de PTR"

print(resoudre_inverse("8.8.8.8"))  # dns.google
```

