import socket

def verifier_port(ip, port, timeout=1):
    """Vérifie si un port TCP est ouvert."""
    with socket.socket(socket.AF_INET, socket.SOCK_STREAM) as s:
        s.settimeout(timeout)
        try:
            s.connect((ip, port))
            return True
        except (socket.timeout, ConnectionRefusedError, OSError):
            return False

# Scanner quelques ports
def scanner_ports(ip, ports):
    ouverts = []
    for port in ports:
        if verifier_port(ip, port, timeout=0.5):
            ouverts.append(port)
            print(f"{ip}:{port} OUVERT")
    return ouverts

# Scan rapide des ports communs
PORTS_COMMUNS = {
    21: "FTP", 22: "SSH", 23: "Telnet", 25: "SMTP",
    53: "DNS", 80: "HTTP", 443: "HTTPS", 445: "SMB",
    3389: "RDP", 4444: "Metasploit", 8080: "HTTP-Alt"
}

ip = "127.0.0.1"
for port, service in PORTS_COMMUNS.items():
    etat = verifier_port(ip, port, timeout=0.3)
    if etat:
        print(f"  {port}/{service}: OUVERT")
